// Calculate success/failure rates
const runs = $input.first().json;
let successCount = 0;
let failCount = 0;
let priceScoutSuccess = 0;
let priceScoutTotal = 0;
let curatorSuccess = 0;
let curatorTotal = 0;
let contentSuccess = 0;
let contentTotal = 0;

const failedPatterns = {};
const lowScores = [];

runs.forEach(run => {
  if (run.success) successCount++;
  else failCount++;

  if (run.agent_type === 'price_scout') {
    priceScoutTotal++;
    if (run.success) priceScoutSuccess++;
  } else if (run.agent_type === 'curator') {
    curatorTotal++;
    if (run.success) curatorSuccess++;
  } else if (run.agent_type === 'content_magic') {
    contentTotal++;
    if (run.success) contentSuccess++;
  }

  if (!run.success) {
    const action = run.action || 'unknown';
    failedPatterns[action] = (failedPatterns[action] || 0) + 1;
  }

  if (run.output_data?.score && run.output_data.score < 0.7) {
    lowScores.push({
      agent: run.agent_type,
      action: run.action,
      score: run.output_data.score,
      timestamp: run.created_at
    });
  }
});

const overallSuccessRate = ((successCount / runs.length) * 100).toFixed(1);

return {
  totalRuns: runs.length,
  successCount,
  failCount,
  overallSuccessRate,
  agentMetrics: {
    priceScout: { success: priceScoutSuccess, total: priceScoutTotal, rate: priceScoutTotal > 0 ? ((priceScoutSuccess/priceScoutTotal)*100).toFixed(1) : 'N/A' },
    curator: { success: curatorSuccess, total: curatorTotal, rate: curatorTotal > 0 ? ((curatorSuccess/curatorTotal)*100).toFixed(1) : 'N/A' },
    contentMagic: { success: contentSuccess, total: contentTotal, rate: contentTotal > 0 ? ((contentSuccess/contentTotal)*100).toFixed(1) : 'N/A' }
  },
  failedPatterns: Object.entries(failedPatterns).sort((a, b) => b[1] - a[1]).slice(0, 5),
  lowScores: lowScores.slice(0, 10),
  allRuns: runs
};

// Generate improvement suggestions
const metrics = $input.first().json;

const suggestions = [];
const urgentIssues = [];

// Check overall success rate
if (parseFloat(metrics.overallSuccessRate) < 85) {
  urgentIssues.push(`Overall success rate is ${metrics.overallSuccessRate}% (target: 95%)`);
}

// Check individual agent performance
if (parseFloat(metrics.agentMetrics.priceScout.rate) < 80) {
  suggestions.push({
    priority: 'high',
    agent: 'Price Scout',
    issue: `Success rate ${metrics.agentMetrics.priceScout.rate}% is below target`,
    suggestion: 'Review OTA API error handling and improve fallback logic'
  });
}

if (parseFloat(metrics.agentMetrics.curator.rate) < 80) {
  suggestions.push({
    priority: 'high',
    agent: 'Experience Curator',
    issue: `Success rate ${metrics.agentMetrics.curator.rate}% is below target`,
    suggestion: 'Review interest matching logic and expand tour database'
  });
}

// Check low-scoring runs
if (metrics.lowScores.length > 0) {
  const topLowAgent = metrics.lowScores.reduce((a, b) => {
    return (a.agent === b.agent) ? a : b;
  });
  suggestions.push({
    priority: 'medium',
    agent: topLowAgent.agent,
    issue: `Multiple low-quality responses (scores < 0.7)`,
    suggestion: 'Ask user for feedback on this agent and update prompts'
  });
}

// Check for repeated failures
if (metrics.failedPatterns.length > 0) {
  metrics.failedPatterns.slice(0, 2).forEach(pattern => {
    suggestions.push({
      priority: 'medium',
      action: pattern[0],
      count: pattern[1],
      suggestion: `Repeated failures (${pattern[1]}x): '${pattern[0]}' - investigate root cause`
    });
  });
}

return {
  hasUrgentIssues: urgentIssues.length > 0,
  urgentIssues,
  suggestions: suggestions.slice(0, 5),
  recommendedActions: [
    { priority: 1, action: 'Review failed agent runs in database' },
    { priority: 2, action: 'A/B test new system prompts with top 10% of suggestions' },
    { priority: 3, action: 'Update agent training data with recent successful examples' }
  ]
};

// Format weekly report for admin
const metrics = $input.first().json;
const suggestions = $input.last().json;

let report = `📊 Lina Point - Weekly AI Performance Report

`;
report += `📈 Overall Metrics:
`;
report += `  Total Runs: ${metrics.totalRuns}
`;
report += `  Success Rate: ${metrics.overallSuccessRate}%
`;
report += `  Failures: ${metrics.failCount}

`;

report += `🤖 Agent Performance:
`;
report += `  Price Scout: ${metrics.agentMetrics.priceScout.rate}% (${metrics.agentMetrics.priceScout.success}/${metrics.agentMetrics.priceScout.total})
`;
report += `  Experience Curator: ${metrics.agentMetrics.curator.rate}% (${metrics.agentMetrics.curator.success}/${metrics.agentMetrics.curator.total})
`;
report += `  Magic Content: ${metrics.agentMetrics.contentMagic.rate}% (${metrics.agentMetrics.contentMagic.success}/${metrics.agentMetrics.contentMagic.total})

`;

if (suggestions.urgentIssues.length > 0) {
  report += `🚨 URGENT ISSUES:
`;
  suggestions.urgentIssues.forEach(issue => {
    report += `  ⚠️ ${issue}
`;
  });
  report += `
`;
}

report += `💡 Top Recommendations:
`;
suggestions.suggestions.slice(0, 3).forEach((s, i) => {
  report += `  ${i+1}. [${s.priority}] ${s.agent || s.action}: ${s.suggestion}
`;
});

report += `
🔗 Full report: https://lina-point-ai-ecosystem.vercel.app/admin
`;

return {
  report,
  summary: {
    totalRuns: metrics.totalRuns,
    successRate: metrics.overallSuccessRate,
    botIssues: suggestions.urgentIssues.length > 0,
    recommendations: suggestions.suggestions.length
  }
};

// Check if we should test new prompts
const suggestions = $input.first().json;

if (suggestions.suggestions.length === 0) {
  return null;
}

// Generate test prompt variations
const testCandidates = suggestions.suggestions.slice(0, 2).map((s, idx) => ({
  id: `test_${new Date().getTime()}_${idx}`,
  targetAgent: s.agent,
  originalSuggestion: s.suggestion,
  testVersion: `v${new Date().getFullYear()}_w${Math.ceil((new Date() - new Date(new Date().getFullYear(), 0, 1)) / 604800000)}`,
  status: 'pending_approval',
  created_at: new Date().toISOString()
}));

return {
  shouldTest: true,
  candidates: testCandidates,
  prompt: `Test the following prompt variations? (Requires manual approval)
${testCandidates.map((c, i) => `${i+1}. [${c.targetAgent}] ${c.originalSuggestion}`).join('
')}`
};
